var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"……보고는 여기까지야.","JPN":"……報告はこれで終わりだよ。","ENG":"...That concludes my report.","TWN":"……報告到此為止。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. 고생 많았네.","JPN":"ああ、ご苦労だった。","ENG":"I see. You've done well.","TWN":"好，辛苦妳了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"정말 많은 정보를 얻었어.","JPN":"本当に多くの情報を得られた。","ENG":"We've gained a great deal of information.","TWN":"我們獲得了許多情報。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"고맙네, 이졸데 양.","JPN":"ありがとう、イゾルデ君。","ENG":"Thank you, Isolde.","TWN":"謝謝妳，伊索德小姐。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"후후…… <color=#ffd34c>똑똑하고 이성적이고 어른스럽고 존경스러운 시니어 이졸데</color>라고 해줬으면 좋겠어.","JPN":"ふふ……<color=#ffd34c>賢くて理性的で分別があって尊敬に値するシニア・イゾルデ</color>と呼んでほしいね。","ENG":"Haha... I'd prefer if you called me <color=#ffd34c>the smart, rational, mature, and admirable Senior Isolde</color>.","TWN":"呵呵……希望你能稱我為<color=#ffd34c>聰明又理性、成熟且令人尊敬的Senior伊索德</color>。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그리고 로터스의 상황에 대해 보고하겠습니다, 최고 관리자님.","JPN":"続いてロータスの状況について報告します、最高管理者様。","ENG":"Then I will proceed with the report on Lotus, Supreme Administrator.","TWN":"那麼我來報告洛德斯的現況，最高管理者。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L10_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"무시하지 마!","JPN":"スルーしないで！","ENG":"Don't ignore me!","TWN":"不要不是我！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 해주겠나, 파티마 양?","JPN":"頼む、ファティマ君。","ENG":"Could you continue, Fatima?","TWN":"妳繼續吧，法蒂瑪小姐？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"우선, 로터스는 완전히 대파되었습니다.","JPN":"まず、ロータスは大破状態です。","ENG":"First, Lotus has been completely devastated.","TWN":"首先，洛德斯完全大敗。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"방위선도 뿌리의 확장을 버티지 못하고 모두 철수한 상황입니다.","JPN":"防衛線も根の拡張に耐えきれず、すべて引き上げました。","ENG":"Even the defense line collapsed under the spread of the roots and has fully withdrawn.","TWN":"防線也無法承受根系的擴張，全部撤退了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그나마 다행스러운 건 사도들이 완전히 이곳에 건너오기 전에 선로전환기를 통해 막은 것이겠군요.","JPN":"使徒が完全にこちらへ渡って来る前に、線路転換器で防げたことだけが不幸中の幸いですね。","ENG":"Fortunately, the Track Switcher stopped the Apostles before they could fully cross over.","TWN":"但值得慶幸的是在使徒們完全跨足至此前，我們透過轉換器阻止它們。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"덕분에 이렇게 대피할 시간을 벌었죠.","JPN":"おかげで、こうやって避難する時間を稼げました。","ENG":"That bought us the time needed to evacuate.","TWN":"多虧如此，才爭取到撤離的時間。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"후후…… 그 사도 자식, 깜짝 놀라는 표정 봤어?","JPN":"ふふ……あの使徒のびっくりする顔見た？","ENG":"Haha... You should've seen that shocked expression on that Apostle's face.","TWN":"呵呵……你看到那個使徒驚訝的表情嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"흥, 진 주제에 혓바닥은 길어가지고.","JPN":"ふん、負けたくせにべらべら喋ってさ。","ENG":"Hmph, so much whining for such a sore loser.","TWN":"哼，明明也沒多厲害，嘴巴倒是很會說。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"잠시나마 철이 들었다고 생각한 제가 바보 같아지는군요.","JPN":"少し大人になったと思った自分がバカでした。","ENG":"I feel foolish for thinking you had matured, even for a moment.","TWN":"以為你稍微懂事的我真是太蠢了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 좋게 생각하게나.","JPN":"はは、ポジティブに捉えようじゃないか。","ENG":"Haha, think of it positively.","TWN":"哈哈，往好處想。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이졸데 양은 더욱 자신감 있게 시니어의 역할을 수행할 수 있게 되었네.","JPN":"イゾルデ君はより自信を持ってシニアの役割を遂行できるようになったんだ。","ENG":"Isolde, you've grown confident enough to truly fulfill the role of Senior.","TWN":"伊索德小姐現在能更有自信地履行前輩的角色了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"흥, 선로전환기로 사도들이 넘어오지 못한 덕분에 대피할 시간을 벌었잖아.","JPN":"ふん、線路転換器のおかげで使徒が来れなくなったから、避難する時間が稼げたんじゃない。","ENG":"Hmph. Thanks to the Track Switcher blocking the Apostles, we had time to evacuate.","TWN":"哼，多虧我使用轉換器讓那些使徒無法越界，才爭取到撤離時間。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"출력을 조절하는 동시에 아티팩트의 동조율을 높여 차원 계면 손상을 막는 내 동시 사고 능력 덕분 아니겠어?","JPN":"出力調整と同時にアーティファクトの同調率を上げて次元界面の損傷を防いだ、私の同時思考能力あってのことでしょ？","ENG":"And it was my multi-thinking that adjusted output and synced the Artifact to prevent dimension surface damage, wasn't it?","TWN":"一邊調整輸出、一邊提高神器的同步率，阻止次元界面受損，不都是靠我的同時思考能力？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"하지만 역시 뿌리가 뻗어 나오는 건 막지 못했네.","JPN":"でも、やっぱり伸びてくる根を止めることはできなかったね。","ENG":"However, I couldn't stop the roots from spreading.","TWN":"不過果然還是沒能阻止根往外蔓延呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아예 효과가 없진 않았네.","JPN":"効果がなかったわけではない。","ENG":"Not entirely ineffective, though.","TWN":"但也不能說完全沒效果。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"뿌리가 뻗어 나오는 속도가 눈에 띄게 느려졌기 때문에 자네들이 무사히 대피할 수 있었으니까.","JPN":"根が伸びる速度が顕著に遅くなったため、君たちが無事避難できたからね。","ENG":"The roots slowed considerably, and that let you all escape safely.","TWN":"根蔓延的速度明顯變慢了，所以你們才能順利撤離。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"누군가에겐 의미 없는 시간 벌이일 수도 있겠으나…….","JPN":"誰かにとっては無意味な時間稼ぎかもしれないが……","ENG":"To some, that might seem like buying meaningless time...","TWN":"對某些人而言，也許只是賺到微不足道的時間……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우리에겐 일분일초가 소중하지.","JPN":"私たちには1分1秒が貴重だ。","ENG":"But for us, every minute and second counts.","TWN":"但對我們來說，一分一秒都很珍貴。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네들이 벌어준 그 시간이 정말 많은 일을 해냈어.","JPN":"君たちが稼いでくれた時間が、私たちの希望を明日へと繋げてくれた。","ENG":"The time you bought allowed us to accomplish much.","TWN":"你們爭取到的那段時間，讓我們完成了很多事。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자랑스러워해도 좋네.","JPN":"誇りに思っていい。","ENG":"You should be proud.","TWN":"妳可以感到很自豪。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"콜로서스 베이스의 도움으로 모든 직할 도시에 배치할 선로전환기가 완성되었어.","JPN":"コロッサスベースの力を借りて、すべての直轄都市に配置する線路転換器を完成させた。","ENG":"With the Colossus Base's help, we've completed Track Switchers for all Direct Control Cities.","TWN":"在巨象基地的協助下，已經完成所有要配置在所有直轄城市的線路轉換器了。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"선로전환기가 사도의 발목을 붙잡을 수 있다는 것도 큰 성과야.","JPN":"線路転換器が使徒を足止めすることができると分かったのも、大きな成果だ。","ENG":"Proving the Track Switcher can hobble an Apostle is a huge success.","TWN":"而且，轉換器能牽制使徒行動這點，本身就是重要的成果。"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"직할 도시를 지키고 있는 관리국에 해당 정보를 전달한 상태지.","JPN":"この情報は、直轄都市を守っている各管理局にも伝えている。","ENG":"That intel has been relayed to the Administration defending the Direct Control Cities.","TWN":"我們已將相關資訊傳達給負責守護直轄城市的管理局。"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"물론… 차원 계면이 융해되는 걸 막아주는 특별한 장치가 필요하지만…….","JPN":"もちろん……次元界面が融解するのを防いでくれる特殊な装置が要るが……","ENG":"Of course... it still needs a special device to prevent the dimension surface meltdown...","TWN":"當然……要阻止次元界面熔解，仍需要特別的裝置……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"유해는 다른 도시에 넘겨주었어.","JPN":"遺骸は他の都市に譲ったよ。","ENG":"The remains have been handed off to another city.","TWN":"殘骸已送往其他城市。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"부디 늦지 않길 바라야겠지.","JPN":"間に合うことを祈るだけだね。","ENG":"Let's hope it isn't too late.","TWN":"希望不會太遲。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"……하지만 우린 제일 큰 걸 잃고 말았어.","JPN":"……でも、私たちはいちばん大きいものを失ってしまった。","ENG":"...But we still lost the most important thing.","TWN":"……但是，我們仍失去了最重要的東西。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"로터스.","JPN":"ロータス。","ENG":"Lotus.","TWN":"洛德斯。"},"stage":{"bg":"OMEN_LOTUS_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"끝내 뿌리를 멈추는 방법, 대균열을 닫는 방법을 알아내지 못했지.","JPN":"結局、根を止める方法や大亀裂を閉じる方法は見つからなかった。","ENG":"We never figured out how to stop the roots or close the Grand Dimension Crevice.","TWN":"我們最終仍無法找出讓根停止的方法，也無法關閉大峽谷。"},"stage":{"bg":"OMEN_LOTUS_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 그렇다고 해서 우리가 완전히 패배한 건 아닐세.","JPN":"だからといって、私たちが完敗したわけではない。","ENG":"Even so, this isn't total defeat.","TWN":"但這並不代表我們輸了。"},"stage":{"bg":"OMEN_LOTUS_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네들이 번 시간, 알아낸 모든 정보들은 전부 우리의 전력이 되고 있으니까.","JPN":"君たちが稼いでくれた時間、入手してくれたすべての情報は全部私たちの戦力になっている。","ENG":"The time you earned and the intel you uncovered all add to our strength.","TWN":"你們爭取的時間、獲得的所有資訊，全都是我們的戰力。"},"stage":{"bg":"OMEN_LOTUS_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"응… 우린 반드시 이길 거야.","JPN":"うん……私たちは必ず勝つ。","ENG":"Yeah... We will win.","TWN":" 嗯……我們一定會贏的。"},"stage":{"bg":"OMEN_LOTUS_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"모두 당신을 믿고 있으니까.","JPN":"みんなあなたのことを信じているから。","ENG":"Everyone believes in you.","TWN":"因為大家都相信你。"},"stage":{"bg":"OMEN_LOTUS_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……고맙네.","JPN":"……ありがとう。","ENG":"...Thank you.","TWN":"……謝謝妳。"},"stage":{"bg":"OMEN_LOTUS_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"반드시…….","JPN":"必ず……","ENG":"I promise...","TWN":"我一定……"},"stage":{"bg":"OMEN_LOTUS_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"반드시 믿음에 부응하도록 하지.","JPN":"必ず、信頼に応えてみせよう。","ENG":"I'll live up to that belief.","TWN":"我一定不會辜負你們的信任。"},"stage":{"bg":"OMEN_LOTUS_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};